 21→interface CartItemRowProps {
 22→  item: CartItem;
 23→  isShopping: boolean;
 24→  onFulfill: () => void;
 25→}
 26→
 27→const SWIPE_THRESHOLD = 120;
 28→
 29→export const CartItemRow = React.memo(function CartItemRow({
 30→  item,
 31→  isShopping,
 32→  onFulfill,
 33→}: CartItemRowProps) {
 34→  const translateX = useSharedValue(0);
 35→  const itemName = item.vaultItemNameSnapshot ?? item.shoppingOnlyName ?? 'Item';
 36→  const price = item.actualPrice ?? item.plannedPrice ?? 0;
 37→  const quantity = item.actualQuantity ?? item.quantity;
 38→
 39→  const panGesture = Gesture.Pan()
 40→    .enabled(isShopping && !item.isFulfilled)
 41→    .onUpdate(e => {
 42→      translateX.value = Math.max(0, e.translationX);
 43→    })
 44→    .onEnd(e => {
 45→      if (e.translationX > SWIPE_THRESHOLD) {
 46→        translateX.value = withSpring(0, motion.snappy);
 47→        runOnJS(onFulfill)();
 48→      } else {
 49→        translateX.value = withSpring(0, motion.snappy);
 50→      }
 51→    });
 52→
 53→  const rowStyle = useAnimatedStyle(() => ({
 54→    transform: [{ translateX: translateX.value }],
 55→  }));
 56→
 57→  const revealStyle = useAnimatedStyle(() => ({
 58→    opacity: translateX.value > 20 ? 1 : 0,
 59→  }));
 60→
 61→  return (
 62→    <View style={styles.container}>
 63→      <Animated.View style={[styles.revealBg, revealStyle]}>
 64→        <MaterialCommunityIcons name="check-circle" size={28} color={colors.success} />
 65→      </Animated.View>
 66→
 67→      <GestureDetector gesture={panGesture}>
 68→        <Animated.View style={[styles.row, rowStyle]}>
 69→          <FulfillmentCheckmark
 70→            animationState={item.fulfillmentAnimationState}
 71→            isFulfilled={item.isFulfilled}
 72→          />
 73→
 74→          <View style={styles.info}>
 75→            <Text
 76→              style={[styles.name, item.shouldStrikethrough && styles.strikethrough]}
 77→            >
 78→              {itemName}
 79→            </Text>
 80→            <Text style={styles.detail}>
 81→              {quantity} x {formatCurrency(price)} - {item.actualStore ?? item.plannedStore}
 82→            </Text>
 83→            {item.actualPrice !== null && item.plannedPrice !== null && (
 84→              <PlannedVsActualPill
 85→                planned={item.plannedPrice}
 86→                actual={item.actualPrice}
 87→              />
 88→            )}
 89→          </View>
 90→
 91→          {isShopping && !item.isFulfilled && (
 92→            <AnimatedPressable
 93→              onPress={onFulfill}
 94→              accessibilityRole="checkbox"
 95→              accessibilityState={{ checked: item.isFulfilled }}
 96→              accessibilityLabel={`Mark ${itemName} as done`}
 97→            >
 98→              <View style={styles.markButton}>
 99→                <Text style={styles.markButtonText}>Done</Text>
100→              </View>
101→            </AnimatedPressable>
102→          )}
103→        </Animated.View>
104→      </GestureDetector>
105→    </View>
106→  );
107→});
