 66→export function CartListScreen({ navigation }: Props) {
 67→  const appState = useAppStore(state => state.appState);
 68→  const draftSelections = useAppStore(state => state.draftSelections);
 69→  const createCart = useAppStore(state => state.createCart);
 70→  const [cartName, setCartName] = useState('');
 71→  const [budget, setBudget] = useState('120');
 72→
 73→  const activeCarts = useMemo(
 74→    () => appState?.vault.carts.filter(c => !c.isDeleted && c.status !== 'completed') ?? [],
 75→    [appState]
 76→  );
 77→
 78→  if (!appState) return null;
 79→
 80→  const selectedItems = Object.entries(draftSelections).map(([itemId, quantity]) => ({
 81→    itemId,
 82→    quantity,
 83→  }));
 84→
 85→  const handleCreateCart = async () => {
 86→    if (!selectedItems.length) return;
 87→    const parsedBudget = Number(budget);
 88→    if (!cartName.trim() || !Number.isFinite(parsedBudget)) return;
 89→    await createCart({ name: cartName, budget: parsedBudget, selectedItems });
 90→    setCartName('');
