110→          <Text style={styles.createTitle}>Quick create</Text>
111→          <Text style={styles.createHint}>
112→            Select items in Vault tab, then create a cart here.
113→          </Text>
114→          <TextInput
115→            style={styles.input}
116→            value={cartName}
117→            onChangeText={setCartName}
118→            placeholder="Cart name"
119→            placeholderTextColor={colors.mutedInk}
120→            accessibilityLabel="Cart name"
121→          />
122→          <TextInput
123→            style={styles.input}
124→            value={budget}
125→            onChangeText={setBudget}
126→            placeholder="Budget"
127→            placeholderTextColor={colors.mutedInk}
128→            keyboardType="decimal-pad"
129→            accessibilityLabel="Budget amount"
130→          />
131→          <AnimatedPressable
132→            style={[styles.createButton, !selectedItems.length && styles.buttonDisabled]}
133→            onPress={() => { handleCreateCart().catch(() => undefined); }}
134→            disabled={!selectedItems.length}
135→            accessibilityRole="button"
136→            accessibilityLabel={`Create cart from ${selectedItems.length} selected items`}
137→            accessibilityState={{ disabled: !selectedItems.length }}
138→          >
